var maxValueAfterReverse = function(nums) {
    const n = nums.length;
    let base = 0;
    for (let i = 0; i < n - 1; i++) base += Math.abs(nums[i] - nums[i+1]);
    let bestGain = 0;
    for (let i = 0; i < n - 1; i++) {
        let gain = Math.abs(nums[0] - nums[i+1]) - Math.abs(nums[i] - nums[i+1]);
        bestGain = Math.max(bestGain, gain);
        gain = Math.abs(nums[n-1] - nums[i]) - Math.abs(nums[i] - nums[i+1]);
        bestGain = Math.max(bestGain, gain);
    }
    let mx = -Infinity, mn = Infinity;
    for (let i = 0; i < n - 1; i++) {
        const a = nums[i], b = nums[i+1];
        mx = Math.max(mx, Math.min(a, b));
        mn = Math.min(mn, Math.max(a, b));
    }
    bestGain = Math.max(bestGain, 2 * Math.max(0, mx - mn));
    return base + bestGain;
};
